INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020015, "", 11, "いかんいかん\n資材の山に埋もれて\nしまうところだった", "", "", "", 302, 10, 111031, "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020016, "", 91, "", "", "", "", 302, "", 0, "");
