INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020019, "", 11, "だが怪我の功名、\n探していた部品を\n偶然にも発見できた", "", "", "", 302, 10, 111031, "");
